"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import Link from "next/link";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { AlertTriangle, Building2, Download, Eye, FileClock, Filter, Menu, RefreshCw, Search, ShieldCheck, SlidersHorizontal, X } from "lucide-react";
import { useMemo, useRef, useState } from "react";
import { useForm } from "react-hook-form";
import { Bar, BarChart, CartesianGrid, Cell, Legend, Line, LineChart, Pie, PieChart, ResponsiveContainer, Scatter, ScatterChart, Tooltip, XAxis, YAxis, ZAxis } from "recharts";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { departmentSchema, type DepartmentFormValues } from "../schemas/department.schema";
import { departmentTypeOptions, useDepartmentFilters } from "../hooks/use-department-filters";
import { type WorklistQuery, useDepartmentDashboard } from "../hooks/use-department-dashboard";
import type { ClaimReadinessStatus, Department, DepartmentDashboardFilters, DepartmentStatus, DepartmentType, QueueStatus } from "../types/department.types";
import { evidenceAgingLabel, formatPercent, formatThb, queueStatusLabel } from "../utils/department-formatters";
import { badgeClass, readableToken } from "../utils/department-status";

const button = "inline-flex min-h-10 items-center justify-center gap-2 rounded-[11px] border border-slate-200 bg-white px-3 py-2 text-[13px] font-black text-slate-900 shadow-sm transition hover:border-blue-200 hover:bg-blue-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 disabled:cursor-not-allowed disabled:opacity-50";
const primaryButton = `${button} border-blue-900 bg-blue-900 text-white hover:bg-blue-950`;
const iconButton = "inline-flex h-10 w-10 items-center justify-center rounded-[11px] border border-slate-200 bg-white text-slate-700 shadow-sm transition hover:border-blue-200 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600";
const card = "rounded-2xl border border-slate-200 bg-white shadow-[0_8px_24px_rgba(15,42,95,.07)]";
const colors = { blue: "#2563EB", navy: "#0F2A5F", green: "#059669", amber: "#D97706", red: "#DC2626", slate: "#64748B", border: "#E2E8F0", sky: "#38BDF8" };

export function DepartmentOperationalIntelligencePage() {
  const [client] = useState(() => new QueryClient());
  return <QueryClientProvider client={client}><DepartmentWorkspace /></QueryClientProvider>;
}

function DepartmentWorkspace() {
  const { filters, updateFilters, resetFilters } = useDepartmentFilters();
  const workspace = useDepartmentDashboard(filters);
  const data = workspace.dashboardQuery.data;
  const [mobileOpen, setMobileOpen] = useState(false);
  const [sheetOpen, setSheetOpen] = useState(false);
  const readinessRef = useRef<HTMLElement>(null);
  const directoryRef = useRef<HTMLElement>(null);
  const worklistRef = useRef<HTMLElement>(null);

  function selectDepartment(departmentId: string) {
    updateFilters({ departmentId });
    workspace.setDirectory((current) => ({ ...current, page: 1 }));
    workspace.setWorklist((current) => ({ ...current, page: 1 }));
  }

  function updateWorklist(patch: Partial<WorklistQuery>) {
    workspace.setWorklist((current) => ({ ...current, ...patch, page: 1 }));
    requestAnimationFrame(() => worklistRef.current?.scrollIntoView({ behavior: "smooth", block: "start" }));
  }

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-950">
      <style>{`.field{min-height:2.5rem;border-radius:.625rem;border:1px solid #E2E8F0;background:#fff;padding:.5rem .75rem;font-size:.875rem;font-weight:600;color:#0F172A;outline:none}.field:focus-visible{outline:2px solid #2563EB;outline-offset:2px}`}</style>
      <Sidebar open={mobileOpen} close={() => setMobileOpen(false)} />
      <div className="flex min-w-0 flex-1 flex-col">
        <Topbar openMenu={() => setMobileOpen(true)} />
        <main className="w-full flex-1 space-y-4 px-3 py-4 sm:px-4 lg:px-6">
          <PageHeader
            data={data}
            loading={workspace.dashboardQuery.isLoading}
            refresh={() => void workspace.dashboardQuery.refetch()}
            exportData={() => workspace.exportMutation.mutate()}
            create={() => setSheetOpen(true)}
            exportPending={workspace.exportMutation.isPending}
          />
          <FilterPanel filters={filters} departments={data?.departments ?? []} updateFilters={updateFilters} reset={() => { resetFilters(); workspace.resetLocalState(); }} />
          {workspace.dashboardQuery.isError ? <ErrorState onRetry={() => void workspace.dashboardQuery.refetch()} /> : null}
          <section className="grid gap-3 md:grid-cols-2 xl:grid-cols-3 min-[1600px]:grid-cols-6" aria-label="Department KPI summary">
            {(data?.kpis ?? []).map((kpi) => (
              <button key={kpi.id} className={`${card} min-h-48 p-4 text-left transition hover:-translate-y-0.5 hover:border-blue-200 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600`} onClick={() => {
                if (kpi.id === "active_departments") { workspace.setDirectory((current) => ({ ...current, status: "active", page: 1 })); directoryRef.current?.scrollIntoView({ behavior: "smooth" }); }
                if (kpi.id === "department_users") { workspace.setDirectory((current) => ({ ...current, sortBy: "manager", page: 1 })); directoryRef.current?.scrollIntoView({ behavior: "smooth" }); }
                if (kpi.id === "today_visits") workspace.setRankingMetric("visitCount");
                if (kpi.id === "claim_ready" || kpi.id === "average_readiness") readinessRef.current?.scrollIntoView({ behavior: "smooth" });
                if (kpi.id === "ai_assisted") updateWorklist({ aiAssisted: true });
              }}>
                <span className="flex items-start justify-between gap-3"><span className="text-xs font-black uppercase text-slate-500">{kpi.label}</span><span className="grid h-9 w-9 place-items-center rounded-lg border border-blue-200 bg-blue-50 text-blue-800"><kpi.icon size={17} /></span></span>
                <strong className="mt-4 block text-3xl font-black text-blue-950">{kpi.value}</strong>
                <span className={`mt-1 block text-xs font-black ${kpi.status === "critical" ? "text-red-700" : kpi.status === "warning" ? "text-amber-700" : kpi.status === "success" ? "text-emerald-700" : "text-blue-700"}`}>{kpi.trend}</span>
                {typeof kpi.progress === "number" ? <span className="mt-4 block h-2 overflow-hidden rounded-full bg-slate-100"><span className="block h-full rounded-full bg-blue-600" style={{ width: `${Math.min(100, Math.max(0, kpi.progress))}%` }} /></span> : null}
                <span className="mt-3 block text-xs leading-5 text-slate-500">{kpi.helper}</span>
              </button>
            ))}
            {workspace.dashboardQuery.isLoading ? Array.from({ length: 6 }, (_, index) => <Skeleton key={index} className="h-48" />) : null}
          </section>
          {data ? (
            <>
              <section className="grid gap-4 xl:grid-cols-[1.15fr_.85fr]">
                <PerformanceRanking data={data.departments} metric={workspace.rankingMetric} direction={workspace.rankingDirection} setMetric={workspace.setRankingMetric} setDirection={workspace.setRankingDirection} selected={filters.departmentId} selectDepartment={selectDepartment} />
                <ClaimReadinessOverview refEl={readinessRef} data={data} updateWorklist={updateWorklist} />
              </section>
              <section className="grid gap-4 xl:grid-cols-2">
                <ChartCard title="Claim Readiness Trend" desc="Actual, Target and Previous Period · รองรับช่วงเวลาและสถานะว่าง">
                  <ResponsiveContainer width="100%" height={300}><LineChart data={data.readiness.trend}><CartesianGrid stroke={colors.border} /><XAxis dataKey="label" /><YAxis domain={[50, 100]} tickFormatter={(value) => `${value}%`} /><Tooltip /><Legend /><Line dataKey="actual" stroke={colors.blue} strokeWidth={3} /><Line dataKey="target" stroke={colors.green} strokeDasharray="5 4" dot={false} /><Line dataKey="previousPeriod" name="Previous Period" stroke="#94A3B8" /></LineChart></ResponsiveContainer>
                </ChartCard>
                <ClaimReadinessByDepartment departments={data.departments} selectDepartment={selectDepartment} />
              </section>
              <section className="grid gap-4 xl:grid-cols-2">
                <QueueSnapshotPanel queue={data.queue} updateWorklist={updateWorklist} />
                <HeatmapPanel cells={data.heatmap} selectDepartment={selectDepartment} />
              </section>
              <section className="grid gap-4 xl:grid-cols-2">
                <EvidencePanel data={data} updateWorklist={updateWorklist} />
                <EconomicPanel data={data} departments={data.departments} selectDepartment={(id) => { selectDepartment(id); updateWorklist({ costStatus: "cost_alert" }); }} updateWorklist={updateWorklist} />
              </section>
              <section className="grid gap-4 xl:grid-cols-2">
                <PriorityMatrix departments={data.departments} selectDepartment={selectDepartment} />
                <AiComparison />
              </section>
              <DepartmentDirectory refEl={directoryRef} workspace={workspace} filters={filters} selectDepartment={selectDepartment} />
              <DepartmentWorklist refEl={worklistRef} workspace={workspace} />
              <section className="grid gap-4 xl:grid-cols-[1fr_.8fr]">
                <RecentCriticalActivity activities={data.activities} />
                <ActionPriorities priorities={data.priorities} />
              </section>
            </>
          ) : null}
        </main>
      </div>
      <CreateDepartmentSheet open={sheetOpen} close={() => setSheetOpen(false)} filters={filters} pending={workspace.createMutation.isPending} onSubmit={(payload) => workspace.createMutation.mutate(payload, { onSuccess: () => setSheetOpen(false) })} />
      <div aria-live="polite" className={`fixed bottom-5 right-5 z-[90] rounded-xl px-4 py-3 text-sm font-bold shadow-xl transition ${workspace.toast ? "translate-y-0 opacity-100" : "pointer-events-none translate-y-3 opacity-0"} ${workspace.toast?.tone === "error" ? "bg-red-700 text-white" : "bg-blue-950 text-white"}`}>{workspace.toast?.message}</div>
    </div>
  );
}

function Sidebar({ open, close }: { open: boolean; close: () => void }) {
  const links = [["Dashboard", "/dashboard"], ["Claim Readiness", "/claim-readiness"], ["Departments", "/organization/departments"], ["Clinic Users", "/admin/users"], ["Audit & Compliance", "/audit-compliance"]];
  return <><button aria-label="Close navigation backdrop" className={`fixed inset-0 z-40 bg-slate-950/35 lg:hidden ${open ? "" : "hidden"}`} onClick={close} /><aside className={`fixed inset-y-0 left-0 z-50 w-[260px] overflow-auto bg-gradient-to-b from-blue-950 to-[#081B3A] p-4 text-white transition lg:sticky lg:top-0 lg:z-auto lg:h-screen ${open ? "translate-x-0" : "-translate-x-full lg:translate-x-0"}`}><div className="flex items-center gap-3 border-b border-white/10 pb-5"><div className="grid h-11 w-11 place-items-center rounded-xl bg-blue-600"><ShieldCheck /></div><div><h1 className="text-sm font-black">Med AI NexSure</h1><p className="text-[11px] text-blue-100">Enterprise Intelligence</p></div></div><nav className="mt-5 space-y-1">{links.map(([label, href]) => <Link key={href} href={href} className={`block rounded-xl px-3 py-2.5 text-sm font-bold ${href === "/organization/departments" ? "border border-sky-300/30 bg-blue-500/25 text-white shadow-[inset_3px_0_0_#38BDF8]" : "text-blue-100 hover:bg-white/10"}`}>{label}</Link>)}</nav></aside></>;
}

function Topbar({ openMenu }: { openMenu: () => void }) {
  return <header className="sticky top-0 z-30 flex h-[70px] items-center gap-3 border-b border-slate-200 bg-white/95 px-4 backdrop-blur lg:px-7"><Button className={`${iconButton} lg:hidden`} aria-label="Open navigation" onClick={openMenu}><Menu size={18} /></Button><label className="flex min-w-0 flex-1 items-center gap-2 rounded-xl border border-slate-200 bg-slate-50 px-3 py-2"><Search size={17} className="text-slate-500" /><span className="sr-only">Global search</span><Input className="min-w-0 flex-1 bg-transparent text-sm outline-none" placeholder="Search patient, visit, claim, department..." /></label><span className="hidden rounded-full border border-blue-200 bg-blue-50 px-3 py-1 text-xs font-black text-blue-800 md:inline-flex">Org Admin</span></header>;
}

function PageHeader({ data, loading, refresh, exportData, create, exportPending }: { data?: { context: { organizationName: string; clinicName: string; lastUpdated: string; canCreateDepartment: boolean; canExport: boolean } }; loading: boolean; refresh: () => void; exportData: () => void; create: () => void; exportPending: boolean }) {
  return <section className="flex flex-col gap-3 lg:flex-row lg:items-end lg:justify-between"><div><p className="text-xs font-black uppercase tracking-[0.16em] text-slate-500">Organization / <span className="text-blue-900">Departments</span></p><h1 className="mt-2 text-2xl font-black tracking-tight text-blue-950 sm:text-3xl">Department Operational Intelligence</h1><p className="mt-1 max-w-4xl text-sm leading-6 text-slate-600">ภาพรวมการกำกับดูแลแผนก, Claim Readiness, Evidence, Queue, SLA และ Economic Intelligence สำหรับผู้ใช้งานที่ได้รับอนุญาต</p><div className="mt-3 flex flex-wrap gap-2 text-xs font-black"><span className="rounded-full border border-blue-200 bg-blue-50 px-3 py-1 text-blue-800">{data?.context.organizationName ?? "Loading organization"}</span><span className="rounded-full border border-blue-200 bg-blue-50 px-3 py-1 text-blue-800">{data?.context.clinicName ?? "Loading clinic"}</span><span className="rounded-full border border-slate-200 bg-white px-3 py-1 text-slate-600">{loading ? "Refreshing..." : `Last updated ${data ? new Date(data.context.lastUpdated).toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" }) : "-"}`}</span></div></div><div className="flex flex-wrap gap-2"><Button className={button} onClick={refresh}><RefreshCw size={16} />Refresh Data</Button><Button className={button} disabled={!data?.context.canExport || exportPending} title={!data?.context.canExport ? "Export requires permission" : undefined} onClick={exportData}><Download size={16} />Export Data</Button><Button className={primaryButton} disabled={!data?.context.canCreateDepartment} title={!data?.context.canCreateDepartment ? "Create requires organization admin permission" : undefined} onClick={create}><Building2 size={16} />Create Department</Button></div></section>;
}

function FilterPanel({ filters, departments, updateFilters, reset }: { filters: DepartmentDashboardFilters; departments: Department[]; updateFilters: (patch: Partial<DepartmentDashboardFilters>) => void; reset: () => void }) {
  return <section className={`${card} p-4`} aria-labelledby="department-filter-title"><div className="mb-3 flex items-start justify-between gap-3"><div><h2 id="department-filter-title" className="font-black text-blue-950"><Filter className="mr-2 inline h-4 w-4" />Dashboard Filters</h2><p className="text-xs text-slate-500">RBAC data scope: Authorized organization and clinic only · จำกัดข้อมูลตามสิทธิ์</p></div><Button className={button} onClick={reset}>Reset Dashboard</Button></div><div className="grid gap-3 md:grid-cols-3 xl:grid-cols-6"><Select label="Organization" value={filters.organizationId} onChange={(value) => updateFilters({ organizationId: value })} options={[["org-nexsure", "NexSure Health Group"]]} /><Select label="Clinic" value={filters.clinicId} onChange={(value) => updateFilters({ clinicId: value })} options={[["clinic-bangkok", "Bangkok CIC"]]} /><Select label="Date Range" value={filters.dateRange} onChange={(value) => updateFilters({ dateRange: value as DepartmentDashboardFilters["dateRange"] })} options={[["today", "Today"], ["yesterday", "Yesterday"], ["last_7_days", "Last 7 Days"], ["last_30_days", "Last 30 Days"], ["this_month", "This Month"]]} /><Select label="Department Type" value={filters.departmentType} onChange={(value) => updateFilters({ departmentType: value as DepartmentType | "all" })} options={departmentTypeOptions.map((item) => [item, readableToken(item)])} /><Select label="Department" value={filters.departmentId} onChange={(value) => updateFilters({ departmentId: value })} options={[["all", "All Departments"], ...departments.map((item) => [item.id, item.name] as [string, string])]} /><Select label="Comparison" value={filters.comparisonPeriod} onChange={(value) => updateFilters({ comparisonPeriod: value as DepartmentDashboardFilters["comparisonPeriod"] })} options={[["previous_day", "Previous Day"], ["previous_period", "Previous Period"], ["previous_week", "Previous Week"], ["previous_month", "Previous Month"]]} /></div><div className="mt-3 flex flex-wrap gap-2 text-xs"><span className="font-black text-slate-600">Active filters:</span>{[filters.dateRange, filters.departmentType, filters.departmentId].map((item) => <span key={item} className="rounded-full border border-blue-200 bg-blue-50 px-2 py-1 font-bold text-blue-800">{readableToken(item)}</span>)}<span className="rounded-full border border-slate-200 bg-white px-2 py-1 text-slate-500">Auto-refresh ready for backend polling</span></div></section>;
}

function PerformanceRanking({ data, metric, direction, setMetric, setDirection, selected, selectDepartment }: { data: Department[]; metric: keyof Department; direction: "asc" | "desc"; setMetric: (metric: keyof Department) => void; setDirection: (direction: "asc" | "desc") => void; selected: string; selectDepartment: (id: string) => void }) {
  const rows = useMemo(() => [...data].sort((a, b) => compareMetric(a[metric], b[metric], direction)), [data, direction, metric]);
  return <ChartCard title="Department Performance Ranking" desc="Click a department to synchronize directory and worklist"><div className="mb-3 flex flex-wrap gap-2"><Select label="Ranking metric" value={String(metric)} onChange={(value) => setMetric(value as keyof Department)} options={[["claimReadyPercentage", "Claim Ready %"], ["visitCount", "Today Visits"], ["averageReadinessScore", "Average Readiness"], ["pendingEvidenceCount", "Pending Evidence"], ["costAlertCount", "Cost Alert Cases"], ["averageWaitMinutes", "Average Waiting Time"]]} /><Button className={button} onClick={() => setDirection(direction === "desc" ? "asc" : "desc")}>{direction === "desc" ? "High to Low" : "Low to High"}</Button><Button className={button} onClick={() => selectDepartment("all")}>Clear Selection</Button></div><div className="grid gap-2">{rows.map((department) => { const value = numericValue(department[metric]); const max = Math.max(...rows.map((item) => numericValue(item[metric])), 1); return <button key={department.id} className={`grid grid-cols-[150px_1fr_70px] items-center gap-3 rounded-lg p-2 text-left text-sm hover:bg-blue-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-blue-600 ${selected === department.id ? "bg-blue-50 ring-2 ring-blue-200" : ""}`} onClick={() => selectDepartment(department.id)}><span className="font-black">{department.name}</span><span className="relative h-3 overflow-hidden rounded-full bg-slate-100"><span className="block h-full rounded-full bg-blue-600" style={{ width: `${(value / max) * 100}%` }} />{metric === "claimReadyPercentage" || metric === "averageReadinessScore" ? <span className="absolute bottom-[-2px] top-[-2px] w-0.5 bg-blue-950" style={{ left: "85%" }} /> : null}</span><strong className="text-right">{formatMetric(metric, department[metric])}</strong></button>; })}</div></ChartCard>;
}

function ClaimReadinessOverview({ refEl, data, updateWorklist }: { refEl: React.RefObject<HTMLElement | null>; data: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>; updateWorklist: (patch: Partial<WorklistQuery>) => void }) {
  const pieData = data.readiness.distribution.map((item) => ({ ...item, color: item.status === "ready" ? colors.green : item.status === "needs_review" ? colors.amber : colors.red }));
  return <ChartCard refEl={refEl} title="Claim Readiness Overview" desc="Ready 85-100 · Needs Review 60-84 · Not Ready 0-59"><div className="grid items-center gap-4 md:grid-cols-[220px_1fr]"><div className="relative h-56"><ResponsiveContainer><PieChart><Pie data={pieData} dataKey="count" innerRadius={64} outerRadius={92} paddingAngle={2} onClick={(entry) => { const payload = chartPayload<{ status: ClaimReadinessStatus }>(entry); if (payload) updateWorklist({ readiness: payload.status }); }}>{pieData.map((entry) => <Cell key={entry.status} fill={entry.color} />)}</Pie><Tooltip /></PieChart></ResponsiveContainer><div className="pointer-events-none absolute inset-0 grid place-items-center text-center"><strong className="text-3xl text-blue-950">{data.readiness.averageScore}</strong><span className="block text-xs text-slate-500">Avg Score</span></div></div><div className="grid gap-2">{pieData.map((item) => <button key={item.status} className="flex items-center justify-between rounded-lg border border-slate-200 p-3 text-left hover:bg-blue-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-blue-600" aria-label={`${item.label}: ${item.percentage}% and ${item.count} cases`} onClick={() => updateWorklist({ readiness: item.status })}><span><span className="mr-2 inline-block h-3 w-3 rounded-full" style={{ background: item.color }} />{item.label}</span><strong>{item.count} · {item.percentage}%</strong></button>)}<div className="grid grid-cols-2 gap-2 text-xs"><Mini label="Target Score" value={`${data.readiness.targetScore}`} /><Mini label="Gap to Target" value={`${(data.readiness.targetScore - data.readiness.averageScore).toFixed(1)}`} /><Mini label="Lower-score Cases" value={`${data.readiness.lowerScoreCases}`} /><Mini label="Total Cases" value={`${data.cases.length}`} /></div></div></div></ChartCard>;
}

function ClaimReadinessByDepartment({ departments, selectDepartment }: { departments: Department[]; selectDepartment: (id: string) => void }) {
  const [mode, setMode] = useState<"percentage" | "count">("percentage");
  const rows = departments.filter((department) => department.visitCount > 0).map((department) => ({ id: department.id, name: department.name, ready: department.claimReadyPercentage ?? 0, review: Math.max(0, 100 - (department.claimReadyPercentage ?? 0) - 8), notReady: 8, visits: department.visitCount }));
  return <ChartCard title="Claim Readiness by Department" desc="Stacked distribution by percentage or case count"><div className="mb-3 flex gap-2"><Button className={mode === "percentage" ? primaryButton : button} onClick={() => setMode("percentage")}>Percentage</Button><Button className={mode === "count" ? primaryButton : button} onClick={() => setMode("count")}>Case Count</Button></div><ResponsiveContainer width="100%" height={310}><BarChart data={rows} layout="vertical" margin={{ left: 42 }}><CartesianGrid stroke={colors.border} horizontal={false} /><XAxis type="number" /><YAxis dataKey="name" type="category" width={120} tick={{ fontSize: 11 }} /><Tooltip /><Legend /><Bar dataKey={mode === "percentage" ? "ready" : "visits"} name="Ready" stackId="a" fill={colors.green} onClick={(entry) => { const payload = chartPayload<{ id: string }>(entry); if (payload) selectDepartment(payload.id); }} /><Bar dataKey="review" name="Needs Review" stackId="a" fill={colors.amber} /><Bar dataKey="notReady" name="Not Ready" stackId="a" fill={colors.red} /></BarChart></ResponsiveContainer></ChartCard>;
}

function QueueSnapshotPanel({ queue, updateWorklist }: { queue: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>["queue"]; updateWorklist: (patch: Partial<WorklistQuery>) => void }) {
  return <ChartCard title="Queue Snapshot" desc="Queue status, SLA exposure, and Thai helper labels"><div className="grid gap-2">{queue.map((item) => <button key={item.status} className="grid grid-cols-[150px_1fr_72px] gap-3 rounded-lg border border-slate-200 p-3 text-left hover:bg-blue-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-blue-600" onClick={() => updateWorklist({ queue: item.status })}><span><strong className="block">{item.label}</strong><span className="text-xs text-slate-500">{item.thaiLabel} · {item.percentage}%</span></span><span><span className="block h-3 rounded-full bg-slate-100"><span className="block h-full rounded-full bg-blue-600" style={{ width: `${item.percentage}%` }} /></span><span className="mt-1 block text-xs text-slate-500">{item.overSla} over SLA · {item.medianWaitMinutes ? `Median ${item.medianWaitMinutes} min` : "No waiting median"}</span></span><strong className="text-right">{item.count}</strong></button>)}</div></ChartCard>;
}

function HeatmapPanel({ cells, selectDepartment }: { cells: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>["heatmap"]; selectDepartment: (id: string) => void }) {
  const departments = Array.from(new Map(cells.map((cell) => [cell.departmentId, cell.departmentName])).entries());
  const times = Array.from(new Set(cells.map((cell) => cell.time)));
  return <ChartCard title="Department Queue Heatmap" desc="Queue Volume · Average Wait Time · Cases Over SLA"><div className="overflow-x-auto"><div className="grid min-w-[680px] gap-1" style={{ gridTemplateColumns: `170px repeat(${times.length}, minmax(72px, 1fr))` }}><div />{times.map((time) => <div key={time} className="grid h-9 place-items-center text-xs font-black text-slate-500">{time}</div>)}{departments.map(([id, name]) => <div key={id} className="contents"><div className="flex items-center text-xs font-black">{name}</div>{times.map((time) => { const cell = cells.find((item) => item.departmentId === id && item.time === time); return <button key={`${id}-${time}`} className={`min-h-12 rounded-lg border text-xs font-black focus-visible:outline focus-visible:outline-2 focus-visible:outline-blue-600 ${heatClass(cell?.severity ?? "low")}`} aria-label={`${name} at ${time}: ${cell?.severity ?? "low"} severity, ${cell?.value ?? 0} cases`} onClick={() => selectDepartment(id)}>{cell?.value ?? 0}<span className="block text-[10px]">{readableToken(cell?.severity ?? "low")}</span></button>; })}</div>)}</div></div><div className="mt-3 flex flex-wrap gap-2 text-xs text-slate-600">{["Low", "Moderate", "High", "Critical"].map((label) => <span key={label} className="rounded-full border border-slate-200 px-2 py-1">{label}</span>)}</div></ChartCard>;
}

function EvidencePanel({ data, updateWorklist }: { data: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>; updateWorklist: (patch: Partial<WorklistQuery>) => void }) {
  const majority = data.evidence.pareto.find((item) => item.cumulativePercentage >= 70) ?? data.evidence.pareto.at(-1);
  return <ChartCard title="Missing Evidence Analysis" desc="Pareto and aging analysis by owner"><div className="grid gap-4 lg:grid-cols-2"><div>{data.evidence.pareto.map((item) => <button key={item.category} className="mb-2 grid w-full grid-cols-[1fr_70px] rounded-lg border border-slate-200 p-3 text-left hover:bg-blue-50 focus-visible:outline focus-visible:outline-2 focus-visible:outline-blue-600" onClick={() => updateWorklist({ evidenceIssue: item.category })}><span><strong className="block text-sm">{item.category}</strong><span className="text-xs text-slate-500">Owner: {item.owner} · {item.percentage}% · cumulative {item.cumulativePercentage}%</span></span><strong className="text-right">{item.count}</strong></button>)}<p className="text-xs leading-5 text-slate-500">Top categories through {majority?.category} represent {majority?.cumulativePercentage}% of displayed issues.</p></div><div>{data.evidence.aging.map((item) => { const total = item.under24 + item.oneToThreeDays + item.overThreeDays; return <button key={item.category} className="mb-2 w-full rounded-lg border border-slate-200 p-3 text-left hover:bg-blue-50" onClick={() => updateWorklist({ evidenceIssue: item.category, slaStatus: "breached" })}><div className="flex justify-between text-sm font-black"><span>{item.category}</span><span>{total}</span></div><div className="mt-2 flex h-3 overflow-hidden rounded-full bg-slate-100"><span className="bg-blue-600" style={{ width: `${(item.under24 / total) * 100}%` }} /><span className="bg-amber-500" style={{ width: `${(item.oneToThreeDays / total) * 100}%` }} /><span className="bg-red-600" style={{ width: `${(item.overThreeDays / total) * 100}%` }} /></div><p className="mt-1 text-xs text-slate-500">Primary owner: {item.primaryOwner} · Overdue {item.overThreeDays}</p></button>; })}<Button className={button} onClick={() => updateWorklist({ queue: "pending_evidence", slaStatus: "breached" })}>View Overdue Cases</Button></div></div></ChartCard>;
}

function EconomicPanel({ data, departments, selectDepartment, updateWorklist }: { data: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>; departments: Department[]; selectDepartment: (id: string) => void; updateWorklist: (patch: Partial<WorklistQuery>) => void }) {
  return <ChartCard title="Economic Intelligence" desc="Decision Support Only"><div className="grid gap-2 sm:grid-cols-4">{[["Average Visit Cost", formatThb(data.economic.averageVisitCost)], ["Expected Cost Range", `${formatThb(data.economic.expectedCostRange[0])}-${formatThb(data.economic.expectedCostRange[1])}`], ["Cost Alert Cases", String(data.economic.costAlertCases)], ["Estimated Claim Value", formatThb(data.economic.estimatedClaimValue)]].map(([label, value]) => <Mini key={label} label={label} value={value} />)}</div><div className="mt-3 rounded-lg border border-blue-200 bg-blue-50 p-3 text-xs leading-5 text-blue-950"><strong>Decision Support Only.</strong> ข้อมูลต้นทุนใช้ประกอบการพิจารณาร่วมกับความซับซ้อนทางคลินิกและ Case Mix ไม่ใช่การปฏิเสธ Claim อัตโนมัติ</div><div className="mt-4 grid gap-4 lg:grid-cols-2"><ResponsiveContainer width="100%" height={260}><BarChart data={departments.filter((item) => item.averageVisitCost > 0)} layout="vertical" margin={{ left: 42 }}><CartesianGrid stroke={colors.border} horizontal={false} /><XAxis type="number" tickFormatter={(value) => `฿${Number(value) / 1000}K`} /><YAxis dataKey="name" type="category" width={120} tick={{ fontSize: 11 }} /><Tooltip formatter={(value) => formatThb(Number(value))} /><Bar dataKey="averageVisitCost" fill={colors.blue} radius={[0, 7, 7, 0]} onClick={(entry) => { const payload = chartPayload<{ id: string }>(entry); if (payload) selectDepartment(payload.id); }} /><Bar dataKey="costBenchmark" fill={colors.amber} radius={[0, 7, 7, 0]} /></BarChart></ResponsiveContainer><ResponsiveContainer width="100%" height={260}><BarChart data={data.economic.distribution}><CartesianGrid stroke={colors.border} vertical={false} /><XAxis dataKey="bucket" tick={{ fontSize: 11 }} /><YAxis /><Tooltip /><Bar dataKey="cases" fill={colors.blue} radius={[7, 7, 0, 0]} onClick={(entry) => { const payload = chartPayload<{ bucket: string }>(entry); if (payload) updateWorklist({ costBucket: payload.bucket, costStatus: payload.bucket.includes("5") || payload.bucket.includes("Over") ? "cost_alert" : "normal" }); }} /></BarChart></ResponsiveContainer></div><div className="mt-2 grid gap-2 sm:grid-cols-4"><Mini label="Median" value="฿3,200" /><Mini label="Average" value={formatThb(data.economic.averageVisitCost)} /><Mini label="90th Percentile" value="฿8,900" /><Mini label="Outliers" value={`${data.economic.costAlertCases}`} /></div></ChartCard>;
}

function PriorityMatrix({ departments, selectDepartment }: { departments: Department[]; selectDepartment: (id: string) => void }) {
  const points = departments.filter((item) => item.averageReadinessScore !== null).map((item) => ({ id: item.id, name: item.name, readiness: item.averageReadinessScore ?? 0, visits: item.visitCount, pending: item.pendingEvidenceCount }));
  return <ChartCard title="Department Priority Matrix" desc="X-axis Readiness Score · Y-axis Visit Volume · Bubble Pending Evidence"><ResponsiveContainer width="100%" height={340}><ScatterChart><CartesianGrid stroke={colors.border} /><XAxis type="number" dataKey="readiness" name="Readiness Score" unit="%" domain={[50, 100]} label={{ value: "Readiness Score", position: "insideBottom", offset: -4 }} /><YAxis type="number" dataKey="visits" name="Visit Volume" label={{ value: "Visit Volume", angle: -90, position: "insideLeft" }} /><ZAxis dataKey="pending" range={[80, 420]} /><Tooltip cursor={{ strokeDasharray: "3 3" }} /><Scatter name="Departments" data={points} fill={colors.blue} onClick={(entry) => { const payload = chartPayload<{ id: string }>(entry); if (payload) selectDepartment(payload.id); }} /></ScatterChart></ResponsiveContainer><p className="sr-only">Quadrants: Immediate Priority, Strong Performance, Monitor Review, Stable. Target line is readiness 85.</p></ChartCard>;
}

function AiComparison() {
  const rows = [["Readiness Score", 86.2, 77.5, "%"], ["Missing Evidence", 18, 31, "%"], ["Completion Time", 14, 23, " min"], ["Human Review", 22, 38, "%"]];
  return <ChartCard title="AI Assisted vs Non-AI Comparison" desc="Operational association only"><div className="grid gap-3 sm:grid-cols-2">{rows.map(([label, ai, nonAi, suffix]) => <div key={label} className="rounded-lg border border-slate-200 p-3"><h3 className="text-sm font-black">{label}</h3><CompareBar label="AI Assisted" value={Number(ai)} suffix={String(suffix)} /><CompareBar label="Non-AI" value={Number(nonAi)} suffix={String(suffix)} warn /></div>)}</div><p className="mt-3 rounded-lg border border-slate-200 bg-slate-50 p-3 text-xs leading-5 text-slate-600">This comparison shows operational association only and does not establish clinical causation.</p></ChartCard>;
}

function DepartmentDirectory({ refEl, workspace, filters, selectDepartment }: { refEl: React.RefObject<HTMLElement | null>; workspace: ReturnType<typeof useDepartmentDashboard>; filters: DepartmentDashboardFilters; selectDepartment: (id: string) => void }) {
  const response = workspace.departmentsQuery.data;
  return <section ref={refEl} className={`${card} overflow-hidden`} aria-labelledby="department-directory-title"><TableHeader title="Department Directory" desc="Search, governance warnings, sortable operational columns" count={response ? `Showing ${response.data.length} of ${response.total}` : "Loading"} /><div className="flex flex-wrap gap-2 border-b border-slate-200 p-4"><label className="flex min-w-[260px] flex-1 items-center gap-2 rounded-xl border border-slate-200 px-3 py-2"><Search size={16} /><Input className="w-full outline-none" placeholder="Search name, code, manager, type" value={workspace.directory.search} onChange={(event) => workspace.setDirectory((current) => ({ ...current, search: event.target.value, page: 1 }))} /></label><Select label="Status" value={workspace.directory.status} onChange={(value) => workspace.setDirectory((current) => ({ ...current, status: value as DepartmentStatus | "all", page: 1 }))} options={[["all", "All Status"], ["active", "Active"], ["inactive", "Inactive"], ["archived", "Archived"]]} /><Select label="Type" value={workspace.directory.type} onChange={(value) => workspace.setDirectory((current) => ({ ...current, type: value as DepartmentType | "all", page: 1 }))} options={departmentTypeOptions.map((item) => [item, readableToken(item)])} /><Button className={button} onClick={() => workspace.setDirectory((current) => ({ ...current, search: "", status: "all", type: "all" }))}>Clear filters</Button><Button className={workspace.directory.view === "table" ? primaryButton : button} onClick={() => workspace.setDirectory((current) => ({ ...current, view: "table" }))}>Table</Button><Button className={workspace.directory.view === "cards" ? primaryButton : button} onClick={() => workspace.setDirectory((current) => ({ ...current, view: "cards" }))}>Cards</Button><Button className={button}><SlidersHorizontal size={16} />Columns</Button></div>{workspace.departmentsQuery.isLoading ? <Skeleton className="m-4 h-72" /> : response && response.data.length ? workspace.directory.view === "table" ? <div className="overflow-x-auto"><table className="w-full min-w-[1320px] text-left text-xs"><thead className="bg-slate-100 text-[10px] uppercase tracking-[.05em] text-slate-600"><tr>{["Department", "Code", "Type", "Manager", "Users", "Visits", "Claim Ready", "Avg Score", "Pending Evidence", "Over SLA", "Avg Wait", "Cost Alerts", "Status", "Actions"].map((head) => <th key={head} className="border-b border-slate-200 px-3 py-3">{head}</th>)}</tr></thead><tbody>{response.data.map((department) => <tr key={department.id} className={`hover:bg-blue-50 ${filters.departmentId === department.id ? "bg-blue-50" : ""}`}><td className="border-b border-slate-100 px-3 py-3"><button className="text-left font-black text-blue-900" onClick={() => selectDepartment(department.id)}>{department.name}<span className="block text-[11px] font-normal text-slate-500">{department.manager ? "Operational intelligence available" : "Manager not assigned - governance warning"}</span></button></td><td className="border-b border-slate-100 px-3 py-3">{department.code}</td><td className="border-b border-slate-100 px-3 py-3"><Badge tone={department.type}>{readableToken(department.type)}</Badge></td><td className="border-b border-slate-100 px-3 py-3">{department.manager?.name ?? <span className="font-bold text-amber-700">Not assigned</span>}</td><td className="border-b border-slate-100 px-3 py-3">{department.userCount}</td><td className="border-b border-slate-100 px-3 py-3">{department.visitCount}</td><td className="border-b border-slate-100 px-3 py-3">{formatPercent(department.claimReadyPercentage)}</td><td className="border-b border-slate-100 px-3 py-3">{department.averageReadinessScore ?? "-"}</td><td className="border-b border-slate-100 px-3 py-3">{department.pendingEvidenceCount}</td><td className="border-b border-slate-100 px-3 py-3">{department.overSlaCount}</td><td className="border-b border-slate-100 px-3 py-3">{department.averageWaitMinutes ? `${department.averageWaitMinutes}m` : "-"}</td><td className="border-b border-slate-100 px-3 py-3">{department.costAlertCount}</td><td className="border-b border-slate-100 px-3 py-3"><Badge tone={department.status}>{readableToken(department.status)}</Badge></td><td className="border-b border-slate-100 px-3 py-3"><Link className={button} href={`/organization/departments/${department.id}`}><Eye size={15} />View Detail</Link></td></tr>)}</tbody></table></div> : <div className="grid gap-3 p-4 md:grid-cols-2 xl:grid-cols-3">{response.data.map((department) => <article key={department.id} className="rounded-xl border border-slate-200 p-4"><h3 className="font-black text-blue-950">{department.name}</h3><p className="text-xs text-slate-500">{department.code} · {readableToken(department.type)}</p><div className="mt-3 grid grid-cols-2 gap-2"><Mini label="Visits" value={`${department.visitCount}`} /><Mini label="Claim Ready" value={formatPercent(department.claimReadyPercentage)} /><Mini label="Pending" value={`${department.pendingEvidenceCount}`} /><Mini label="Cost Alerts" value={`${department.costAlertCount}`} /></div><Link className={`${button} mt-3 w-full`} href={`/organization/departments/${department.id}`}>View Detail</Link></article>)}</div> : <Empty title="No departments found" />}</section>;
}

function DepartmentWorklist({ refEl, workspace }: { refEl: React.RefObject<HTMLElement | null>; workspace: ReturnType<typeof useDepartmentDashboard> }) {
  const response = workspace.worklistQuery.data;
  const chips = Object.entries(workspace.worklist).filter(([key, value]) => !["page", "pageSize", "search"].includes(key) && value !== "all" && value !== "");
  return <section ref={refEl} className={`${card} overflow-hidden`} aria-labelledby="department-worklist-title"><TableHeader title="Department Case Worklist" desc="Masked patient identifiers, claim readiness, SLA, cost, and evidence filters" count={response ? `Showing ${response.data.length} of ${response.total}` : "Loading"} /><div className="flex flex-wrap gap-2 border-b border-slate-200 p-4"><label className="flex min-w-[260px] flex-1 items-center gap-2 rounded-xl border border-slate-200 px-3 py-2"><Search size={16} /><Input className="w-full outline-none" placeholder="Search visit, masked patient, department, provider" value={workspace.worklist.search} onChange={(event) => workspace.setWorklist((current) => ({ ...current, search: event.target.value, page: 1 }))} /></label><Select label="Readiness" value={workspace.worklist.readiness} onChange={(value) => workspace.setWorklist((current) => ({ ...current, readiness: value as ClaimReadinessStatus | "all", page: 1 }))} options={[["all", "All Readiness"], ["ready", "Ready"], ["needs_review", "Needs Review"], ["not_ready", "Not Ready"]]} /><Select label="Queue" value={workspace.worklist.queue} onChange={(value) => workspace.setWorklist((current) => ({ ...current, queue: value as QueueStatus | "all", page: 1 }))} options={[["all", "All Queue"], ["completed", "Completed"], ["in_consultation", "In Consultation"], ["pending_evidence", "Pending Evidence"], ["waiting", "Waiting"], ["pharmacy", "Pharmacy"]]} /><Select label="Cost Status" value={workspace.worklist.costStatus} onChange={(value) => workspace.setWorklist((current) => ({ ...current, costStatus: value as WorklistQuery["costStatus"], page: 1 }))} options={[["all", "All Cost"], ["normal", "Normal"], ["cost_alert", "Cost Alert"]]} /><Button className={button} onClick={() => workspace.setWorklist({ search: "", readiness: "all", queue: "all", costStatus: "all", evidenceIssue: "all", slaStatus: "all", aiAssisted: "all", costBucket: "all", page: 1, pageSize: 8 })}>Clear filters</Button></div><div className="flex flex-wrap gap-2 px-4 py-3 text-xs"><strong>Chart filters:</strong>{chips.length ? chips.map(([key, value]) => <button key={key} className="rounded-full border border-blue-200 bg-blue-50 px-2 py-1 font-bold text-blue-800" onClick={() => workspace.setWorklist((current) => ({ ...current, [key]: "all", page: 1 }))}>{readableToken(String(value))} x</button>) : <span className="text-slate-500">No chart filters applied</span>}</div>{workspace.worklistQuery.isLoading ? <Skeleton className="m-4 h-72" /> : response && response.data.length ? <div className="overflow-x-auto"><table className="w-full min-w-[1420px] text-left text-xs"><thead className="bg-slate-100 text-[10px] uppercase tracking-[.05em] text-slate-600"><tr>{["Visit ID", "Patient Masked", "Department", "Visit Date", "Provider", "Queue Status", "AI Assisted", "Readiness Score", "Claim Status", "Missing Evidence", "Evidence Aging", "Cost Status", "SLA Status", "Last Updated", "Actions"].map((head) => <th key={head} className="border-b border-slate-200 px-3 py-3">{head}</th>)}</tr></thead><tbody>{response.data.map((item) => <tr key={item.id} className="hover:bg-blue-50"><td className="border-b border-slate-100 px-3 py-3 font-black text-blue-800">{item.visitId}</td><td className="border-b border-slate-100 px-3 py-3">{item.patientMasked}</td><td className="border-b border-slate-100 px-3 py-3">{item.departmentName}</td><td className="border-b border-slate-100 px-3 py-3">{item.visitDate}</td><td className="border-b border-slate-100 px-3 py-3">{item.provider}</td><td className="border-b border-slate-100 px-3 py-3"><Badge tone="info">{queueStatusLabel(item.queueStatus)}</Badge></td><td className="border-b border-slate-100 px-3 py-3"><Badge tone={item.aiAssisted ? "info" : "success"}>{item.aiAssisted ? "AI Assisted" : "Not Used"}</Badge></td><td className="border-b border-slate-100 px-3 py-3"><strong>{item.readinessScore}</strong><span className="ml-2 inline-block h-2 w-16 rounded-full bg-slate-100 align-middle"><span className="block h-full rounded-full bg-blue-600" style={{ width: `${item.readinessScore}%` }} /></span></td><td className="border-b border-slate-100 px-3 py-3">{readableToken(item.claimStatus)}</td><td className="border-b border-slate-100 px-3 py-3">{item.missingEvidence.join(", ") || "Complete"}</td><td className="border-b border-slate-100 px-3 py-3">{evidenceAgingLabel(item.evidenceAgingHours)}</td><td className="border-b border-slate-100 px-3 py-3"><Badge tone={item.costStatus}>{readableToken(item.costStatus)}</Badge></td><td className="border-b border-slate-100 px-3 py-3"><Badge tone={item.slaStatus}>{readableToken(item.slaStatus)}</Badge></td><td className="border-b border-slate-100 px-3 py-3">{item.lastUpdated}</td><td className="border-b border-slate-100 px-3 py-3"><div className="flex gap-2"><Link className={button} href={`/visits/${item.visitId}`}>View Detail</Link><Button className={button}>Create Task</Button></div></td></tr>)}</tbody></table></div> : <Empty title="No cases found" />}</section>;
}

function RecentCriticalActivity({ activities }: { activities: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>["activities"] }) {
  const [tab, setTab] = useState<"all" | "critical" | "access" | "export">("all");
  const rows = activities.filter((item) => tab === "all" || item.type === tab);
  return <ChartCard title="Recent Critical Activity" desc="Read-only audit-aware event stream"><div className="mb-3 flex flex-wrap gap-2">{[["all", "All Activity"], ["critical", "Critical Changes"], ["access", "Access & Permission"], ["export", "Data Export"]].map(([id, label]) => <Button key={id} className={tab === id ? primaryButton : button} onClick={() => setTab(id as typeof tab)}>{label}</Button>)}</div><div className="grid gap-2">{rows.map((item) => <article key={item.id} className="grid grid-cols-[36px_1fr_auto] gap-3 border-b border-slate-100 py-3"><span className="grid h-9 w-9 place-items-center rounded-lg bg-blue-50 text-blue-800"><FileClock size={16} /></span><span><strong className="block text-sm">{item.title}</strong><span className="text-xs text-slate-500">{item.actor} · {item.role} · {item.source} {item.correlationId ? `· ${item.correlationId}` : ""}</span></span><span className="text-right"><Badge tone={item.severity}>{readableToken(item.severity)}</Badge><time className="block text-[11px] text-slate-500">{item.time}</time></span></article>)}</div></ChartCard>;
}

function ActionPriorities({ priorities }: { priorities: NonNullable<ReturnType<typeof useDepartmentDashboard>["dashboardQuery"]["data"]>["priorities"] }) {
  return <ChartCard title="Action Priorities" desc="Decision support only · Human Review Required">{priorities.map((item, index) => <article key={item.id} className="mb-2 rounded-xl border border-slate-200 p-3"><div className="flex justify-between gap-3"><strong>#{index + 1} {item.title}</strong><Badge tone={item.severity}>{readableToken(item.severity)}</Badge></div><p className="mt-1 text-xs text-slate-500">{item.supportingMetric}</p><span className="mt-2 inline-flex rounded-full border border-blue-200 bg-blue-50 px-2 py-1 text-[10px] font-black text-blue-800">Human Review Required</span></article>)}</ChartCard>;
}

function CreateDepartmentSheet({ open, close, filters, pending, onSubmit }: { open: boolean; close: () => void; filters: DepartmentDashboardFilters; pending: boolean; onSubmit: (payload: DepartmentFormValues) => void }) {
  const { register, handleSubmit, formState: { errors }, reset } = useForm<DepartmentFormValues>({ resolver: zodResolver(departmentSchema), defaultValues: { organizationId: filters.organizationId, clinicId: filters.clinicId, name: "", code: "", type: "clinical", managerId: null, description: "", phoneExtension: "", email: "", operatingHours: "", costCenterCode: "", aiClinicalAccess: true, status: "active" } });
  if (!open) return null;
  return <div className="fixed inset-0 z-[80] flex justify-end bg-slate-950/45" role="dialog" aria-modal="true" aria-labelledby="create-department-title"><form className="flex h-full w-full max-w-2xl flex-col bg-white shadow-2xl" onSubmit={handleSubmit(onSubmit)}><div className="border-b border-slate-200 p-5"><div className="flex items-start justify-between gap-3"><div><h2 id="create-department-title" className="text-xl font-black text-blue-950">Create Department</h2><p className="text-sm text-slate-500">สร้างแผนกภายใต้สิทธิ์ Organization และ Clinic ที่ได้รับอนุญาต</p></div><Button className={iconButton} onClick={close} aria-label="Close create department sheet"><X size={18} /></Button></div></div><div className="grid flex-1 gap-4 overflow-y-auto p-5 md:grid-cols-2"><Field label="Organization" error={errors.organizationId?.message}><select className="field" {...register("organizationId")}><option value="org-nexsure">NexSure Health Group</option></select></Field><Field label="Clinic" error={errors.clinicId?.message}><select className="field" {...register("clinicId")}><option value="clinic-bangkok">Bangkok CIC</option></select></Field><Field label="Department Name" error={errors.name?.message}><input className="field" {...register("name")} /></Field><Field label="Department Code" error={errors.code?.message}><input className="field" placeholder="ER-01" {...register("code")} /></Field><Field label="Department Type" error={errors.type?.message}><select className="field" {...register("type")}><option value="clinical">Clinical</option><option value="diagnostic">Diagnostic</option><option value="operational">Operational</option></select></Field><Field label="Department Manager" error={errors.managerId?.message}><select className="field" {...register("managerId")}><option value="">Not assigned</option><option value="mgr-1">Dr. Anan S.</option><option value="mgr-2">Dr. Benjawan R.</option><option value="mgr-4">Krit P.</option><option value="mgr-5">Mayuree L.</option></select></Field><Field label="Phone Extension" error={errors.phoneExtension?.message}><input className="field" {...register("phoneExtension")} /></Field><Field label="Email" error={errors.email?.message}><input className="field" type="email" {...register("email")} /></Field><Field label="Operating Hours" error={errors.operatingHours?.message}><input className="field" {...register("operatingHours")} /></Field><Field label="Cost Center Code" error={errors.costCenterCode?.message}><input className="field" {...register("costCenterCode")} /></Field><Field label="Description" error={errors.description?.message} full><textarea className="field min-h-24" {...register("description")} /></Field><label className="flex items-center justify-between rounded-xl border border-blue-200 bg-blue-50 p-3 text-sm font-black text-blue-950 md:col-span-2">AI Clinical Access<Checkbox {...register("aiClinicalAccess")} defaultChecked /></label><Field label="Status" error={errors.status?.message}><select className="field" {...register("status")}><option value="active">Active</option><option value="inactive">Inactive</option></select></Field><p className="text-xs leading-5 text-slate-500 md:col-span-2">Backend must enforce authorization and write audit logs for creation. Frontend checks are helper controls only.</p></div><div className="flex justify-end gap-2 border-t border-slate-200 bg-slate-50 p-5"><Button className={button} onClick={() => { reset(); close(); }}>Cancel</Button><Button className={primaryButton} disabled={pending} type="submit">{pending ? "Creating..." : "Create Department"}</Button></div></form></div>;
}

function ChartCard({ title, desc, children, refEl }: { title: string; desc: string; children: React.ReactNode; refEl?: React.RefObject<HTMLElement | null> }) {
  return <section ref={refEl} className={`${card} min-w-0 p-4`}><h2 className="font-black text-blue-950">{title}</h2><p className="mb-3 text-xs leading-5 text-slate-500">{desc}</p>{children}</section>;
}
function Select({ label, value, options, onChange }: { label: string; value: string; options: [string, string][]; onChange: (value: string) => void }) { return <label className="grid gap-1 text-xs font-black text-slate-600"><span>{label}</span><select className="h-10 rounded-[10px] border border-slate-200 bg-white px-3 text-sm font-semibold text-slate-900 focus-visible:outline focus-visible:outline-2 focus-visible:outline-blue-600" value={value} onChange={(event) => onChange(event.target.value)}>{options.map(([id, labelText]) => <option key={id} value={id}>{labelText}</option>)}</select></label>; }
function Badge({ tone, children }: { tone: Parameters<typeof badgeClass>[0]; children: React.ReactNode }) { return <span className={`inline-flex whitespace-nowrap rounded-full border px-2 py-1 text-[10px] font-black ${badgeClass(tone)}`}>{children}</span>; }
function Mini({ label, value }: { label: string; value: string }) { return <div className="rounded-lg border border-slate-200 bg-slate-50 p-3"><div className="text-[11px] text-slate-500">{label}</div><div className="mt-1 text-base font-black text-blue-950">{value}</div></div>; }
function Skeleton({ className }: { className: string }) { return <div className={`animate-pulse rounded-2xl bg-slate-200/70 ${className}`} />; }
function Empty({ title }: { title: string }) { return <div className="p-10 text-center text-sm text-slate-500"><AlertTriangle className="mx-auto mb-2 text-slate-400" /><strong>{title}</strong><br />ไม่พบแผนกตามเงื่อนไขที่เลือก กรุณาปรับตัวกรองแล้วลองอีกครั้ง</div>; }
function ErrorState({ onRetry }: { onRetry: () => void }) { return <section className={`${card} p-8 text-center`}><AlertTriangle className="mx-auto text-red-700" /><h2 className="mt-3 font-black">Unable to load department dashboard</h2><p className="mt-1 text-sm text-slate-500">ไม่สามารถโหลดข้อมูลได้ กรุณาลองใหม่อีกครั้ง</p><Button className={`${button} mt-4`} onClick={onRetry}>Retry</Button></section>; }
function TableHeader({ title, desc, count }: { title: string; desc: string; count: string }) { return <div className="flex flex-col gap-2 border-b border-slate-200 p-4 md:flex-row md:items-start md:justify-between"><div><h2 className="font-black text-blue-950">{title}</h2><p className="text-xs leading-5 text-slate-500">{desc}</p></div><span className="rounded-full border border-blue-200 bg-blue-50 px-3 py-1 text-xs font-black text-blue-800">{count}</span></div>; }
function Field({ label, error, full, children }: { label: string; error?: string; full?: boolean; children: React.ReactNode }) { return <label className={`grid gap-1 text-sm font-black text-slate-700 ${full ? "md:col-span-2" : ""}`}>{label}{children}{error ? <span className="text-xs text-red-700">{error}</span> : null}</label>; }
function CompareBar({ label, value, suffix, warn }: { label: string; value: number; suffix: string; warn?: boolean }) { return <div className="mt-3 grid grid-cols-[90px_1fr_56px] items-center gap-2 text-xs"><span>{label}</span><span className="h-2 rounded-full bg-slate-100"><span className={`block h-full rounded-full ${warn ? "bg-amber-500" : "bg-blue-600"}`} style={{ width: `${Math.min(100, value)}%` }} /></span><strong>{value}{suffix}</strong></div>; }
function compareMetric(left: string | number | null | object, right: string | number | null | object, direction: "asc" | "desc") { const a = numericValue(left); const b = numericValue(right); return direction === "asc" ? a - b : b - a; }
function numericValue(value: string | number | null | object) { return typeof value === "number" ? value : Number(value ?? 0) || 0; }
function formatMetric(metric: keyof Department, value: Department[keyof Department]) { if (metric === "claimReadyPercentage") return formatPercent(value as number | null); if (metric === "averageWaitMinutes") return value ? `${value}m` : "-"; return typeof value === "number" ? String(value) : "-"; }
function heatClass(severity: string) { if (severity === "critical") return "border-blue-900 bg-blue-900 text-white"; if (severity === "high") return "border-blue-500 bg-blue-500 text-white"; if (severity === "moderate") return "border-blue-200 bg-blue-200 text-blue-950"; return "border-blue-100 bg-blue-50 text-blue-900"; }
function chartPayload<T>(entry: unknown): T | null {
  if (!entry || typeof entry !== "object" || !("payload" in entry)) return null;
  return (entry as { payload?: T }).payload ?? null;
}
